#include<bits/stdc++.h>
using namespace std;
long long n, kk, dp[106][106][106], a[106][106];
int main() {
	cin >> n >> kk;
	for (int i = 1; i <= n; i++) {
		for (int j = 1; j <= i; j++) {
			cin >> a[i][j];
		}
	}
	for (int k = 0; k <= n + 1; k++) {
		for (int i = 0; i <= n + 1; i++) {
			for (int j = 0; j <= i + 1; j++) {
				dp[i][j][k] = LLONG_MIN/3;
			}
		}
	}
	for (int i = 1; i <= n; i++) {
		for (int j = 1; j <= i; j++) {
			for (int k = 0; k <= kk; k++) {
				if (i == 1 && j == 1) {
					dp[i][j][k] = a[i][j];
					if(k >= 1) dp[i][j][k] = a[i][j] * 3;
					continue;
				}
				if (k == 0) dp[i][j][k] = max(dp[i - 1][j - 1][k] + a[i][j], dp[i - 1][j][k] + a[i][j]);
				else dp[i][j][k] = max(max(dp[i - 1][j][k], dp[i - 1][j - 1][k]) + a[i][j], max(dp[i - 1][j][k - 1], dp[i - 1][j - 1][k - 1]) + a[i][j] * 3);
			}
		}
	}

	long long maxx = LLONG_MIN;
	for (int i = 1; i <= n; i++) {
		for(int k=0;k<=n;k++){
            maxx = max(dp[n][i][k], maxx);
        }
	}
	cout << maxx;
	return 0;
}
